32	function computeComponentPremium(items: Array<{ type: string }>): number {
33	  const counts = new Map<string, number>();
34	  for (const item of items) {
35	    if (COMPONENT_TYPES.has(item.type)) {
36	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
37	    }
38	  }
39	  let premium = 0;
40	  for (const [type, count] of counts) {
41	    if (count === BLOCK_SIZE) {
42	      premium += BLOCK_PREMIUM;
43	    } else {
44	      premium += count * (BASE_PREMIUMS[type] ?? 0);
45	    }
46	  }
47	  return premium;
48	}
