50	function computeQuotePremium(items: Item[], customer: { yearsWithMHPCO: number }, isFollowUp: boolean): number {
51	  const standardItems = items.filter((item) => !COMPONENT_TYPES.has(item.type));
52	  let policyBase = 0;
53	  let itemSurcharges = 0;
54	  for (const item of standardItems) {
55	    const basePremium = BASE_PREMIUMS[item.type] ?? 0;
56	    policyBase += basePremium;
57	    if (item.cursed) {
58	      itemSurcharges += basePremium * 0.5;
59	    }
60	    if ((item.enchantment ?? 0) >= 5) {
61	      itemSurcharges += basePremium * 0.3;
62	    }
63	  }
64	  const componentPremium = computeComponentPremium(items);
65	  policyBase += componentPremium;
66	  const firstInsurance = policyBase * 0.1;
67	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
68	  const followUpDiscount = isFollowUp ? policyBase * 0.15 : 0;
69	  return policyBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
70	}
