73	  let quoteCount = 0;
74	  const results = scenario.steps.map((step) => {
75	    if (step.op === "quote") {
76	      const items = step.items ?? [];
77	      const isFollowUp = quoteCount > 0;
78	      quoteCount++;
79	      return { premium: computeQuotePremium(items, scenario.customer, isFollowUp) };
80	    }
81	    return {};
82	  });
83	  return { results };
